-- Menu choice refinements for bento, nigiri/sashimi, and item-specific add-ons.

UPDATE categories
SET description = 'Chef-selected assortments and shareable trays for groups.'
WHERE slug IN ('moriawase-tray', 'moriawase');

UPDATE categories
SET description = 'Complete bento meals served with rice, grilled vegetables, orange, and selected sides.'
WHERE slug = 'bento-box';

ON CONFLICT (id) DO UPDATE SET
  name = EXCLUDED.name,
  price_modifier = EXCLUDED.price_modifier,
  sort_order = EXCLUDED.sort_order;

ON CONFLICT (id) DO UPDATE SET
  category_id = EXCLUDED.category_id,
  name = EXCLUDED.name,
  description = EXCLUDED.description,
  price = EXCLUDED.price,
  is_available = EXCLUDED.is_available,
  has_roll_options = EXCLUDED.has_roll_options,
  sort_order = EXCLUDED.sort_order;

DELETE FROM menu_item_options
WHERE menu_option_id = '33333333-3333-3333-3333-333333333301'
  AND menu_item_id <> 'a1000001-0000-0000-0000-00000000000d';

DELETE FROM menu_item_options
WHERE menu_option_id = '33333333-3333-3333-3333-333333333303'
  AND menu_item_id NOT IN (
    'a1000001-0000-0000-0000-000000000007',
    'a1000001-0000-0000-0000-00000000000b'
  );

DELETE FROM menu_item_options
WHERE menu_item_id IN (
  SELECT id FROM menu_items WHERE category_id = 'c1000001-0000-0000-0000-000000000001'
)
OR menu_item_id IN (
  'a1000001-0000-0000-0000-000000000016',
  'a1000001-0000-0000-0000-000000000025'
);

ON CONFLICT DO NOTHING;
